#include<bits/stdc++.h>
using namespace std;
int dp[105][10005];
int main()
{
	dp[1][0] = dp[2][0] = dp[2][1] = dp[0][0] = 1;
	int n, k;
	cin >> n >> k;
	for(int i = 3; i <= n; i++)
		for(int j = 0; j <= k; j++)
			for(int k = 0; k <= i - 1 && j - k >= 0; k++)
				dp[i][j] = (dp[i - 1][j - k] + dp[i][j]) % 10000;

	cout << dp[n][k];
}
